<template>
  <Screen>
    <div v-if="step === 'intro'" class="practice-instructions">
      <h2>Practice</h2>
      <p>
        You will now complete a short practice round to understand how the task works.
        Please select the object that you think the speaker is referring to.
      </p>
      <button @click="startPractice">Start practice</button>
    </div>

    <div v-if="step === 'trial'">
      <div class="block-row">
        <div
          v-for="(trial, index) in practiceTrials"
          :key="trial.id"
          class="trial-slot"
          :class="{ hidden: index > currentGrid }"
        >
          <h3 class="utterance">{{ trial.utterance }}</h3>

          <div class="grid-wrapper">
            <img :src="trial.image" class="stimulus" />

            <button
              class="cell top-left"
              :disabled="index !== currentGrid || hasResponse(index)"
              @click="selectObject('topLeft')"
            />
            <button
              class="cell top-right"
              :disabled="index !== currentGrid || hasResponse(index)"
              @click="selectObject('topRight')"
            />
            <button
              class="cell bottom-left"
              :disabled="index !== currentGrid || hasResponse(index)"
              @click="selectObject('bottomLeft')"
            />
            <button
              class="cell bottom-right"
              :disabled="index !== currentGrid || hasResponse(index)"
              @click="selectObject('bottomRight')"
            />

            <div
              v-if="responses[index]"
              class="selection-marker"
              :class="responses[index].response"
            />
          </div>
        </div>
      </div>
    </div>

    <div v-if="step === 'done'" class="practice-instructions">
      <h2>End of practice</h2>
      <p>
        The practice round is now complete. The real experiment will begin on the next screen.
      </p>
      <button @click="$magpie.nextScreen()">Continue</button>
    </div>
  </Screen>
</template>

<script>
export default {
  name: "PracticeBlock",
  props: {
    practiceTrials: Array
  },
  data() {
    return {
      step: "intro",
      currentGrid: 0,
      blockStartTime: null,
      gridStartTime: null,
      responses: []
    };
  },
  methods: {
    startPractice() {
      this.currentGrid = 0;
      this.responses = [];
      this.step = "trial";
      this.blockStartTime = performance.now();
      this.gridStartTime = performance.now();
    },

    hasResponse(index) {
      return Boolean(this.responses[index]);
    },

    selectObject(cell) {
      const now = performance.now();
      const trial = this.practiceTrials[this.currentGrid];

      const correctAnswers = Array.isArray(trial.correctAnswer)
        ? trial.correctAnswer
        : [trial.correctAnswer];

      const isCorrect = correctAnswers.includes(cell);

      this.responses[this.currentGrid] = {
        trial_type: "practice_object_trial",
        trial_id: trial.id,
        phase: trial.phase,
        block_id: trial.block_id,
        trial_in_block: trial.trial_in_block,
        condition: trial.condition,
        utterance: trial.utterance,
        grey_cell: trial.greyCell,
        response: cell,
        correct_answer: correctAnswers.join(","),
        correct: isCorrect,
        rt: now - this.gridStartTime
      };

      if (this.currentGrid < this.practiceTrials.length - 1) {
        this.currentGrid += 1;
        this.gridStartTime = performance.now();
      } else {
        this.finishPractice(now);
      }
    },

    finishPractice(endTime) {
      const blockRT = endTime - this.blockStartTime;

      const trialData = {
        trial_type: "practice_block",
        phase: "practice",
        block_id: 0,
        block_rt: blockRT,
        block_responses_json: JSON.stringify(this.responses)
      };

      this.responses.forEach((r, i) => {
        const n = i + 1;
        trialData[`practice_trial_id_${n}`] = r.trial_id;
        trialData[`practice_trial_in_block_${n}`] = r.trial_in_block;
        trialData[`practice_condition_${n}`] = r.condition;
        trialData[`practice_utterance_${n}`] = r.utterance;
        trialData[`practice_grey_cell_${n}`] = r.grey_cell;
        trialData[`practice_response_${n}`] = r.response;
        trialData[`practice_correct_answer_${n}`] = r.correct_answer;
        trialData[`practice_correct_${n}`] = r.correct;
        trialData[`practice_rt_${n}`] = r.rt;
      });

      this.$magpie.addTrialData(trialData);
      this.step = "done";
    }
  }
};
</script>

<style scoped>
.practice-instructions {
  width: 600px;
  margin: 0 auto;
  text-align: justify;
}

.practice-instructions h2 {
  text-align: center;
}

.practice-instructions button {
  display: block;
  margin: 20px auto;
}

.block-row {
  display: flex;
  gap: 18px;
  justify-content: center;
  align-items: flex-start;
  width: 100%;
}

.trial-slot {
  width: 260px;
}

.trial-slot.hidden {
  visibility: hidden;
}

.utterance {
  text-align: center;
  font-size: 20px;
  min-height: 45px;
  margin-bottom: 8px;
}

.grid-wrapper {
  position: relative;
  width: 260px;
  line-height: 0;
}

.stimulus {
  width: 100%;
  display: block;
}

.cell {
  position: absolute;
  background: transparent;
  border: none;
  padding: 0;
  margin: 0;
  appearance: none;
  -webkit-appearance: none;
  opacity: 0;
  cursor: pointer;
}

.top-left {
  top: 0;
  left: 0;
  width: 50%;
  height: 50%;
}

.top-right {
  top: 0;
  left: 50%;
  width: 50%;
  height: 50%;
}

.bottom-left {
  top: 50%;
  left: 0;
  width: 50%;
  height: 50%;
}

.bottom-right {
  top: 50%;
  left: 50%;
  width: 50%;
  height: 50%;
}

.selection-marker {
  position: absolute;
  width: 13px;
  height: 13px;
  border-radius: 50%;
  background: black;
  transform: translate(-50%, -50%);
  pointer-events: none;
}

.selection-marker.topLeft {
  top: 25%;
  left: 25%;
}

.selection-marker.topRight {
  top: 25%;
  left: 75%;
}

.selection-marker.bottomLeft {
  top: 75%;
  left: 25%;
}

.selection-marker.bottomRight {
  top: 75%;
  left: 75%;
}
</style>